#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int main()
{
    int n,m,i,j,s=0;
    scanf("%d%d",&n,&m);
    if(m<n)
    {
        j=n;
        n=m;
        m=j;
    }
    if(n==1)
    {
        printf("%d",m);
    }
    else if(n==2)
    {
        s=m/4*4;
        if(m%4==1)
        {
            s+=2;
        }
        else if(m%4>1)
        {
            s+=4;
        }
        printf("%d",s);
    }
    else
    {
        s=n*m/2+((m*n)%2);
    printf("%d",s);
    }

    return 0;
}

